"use client";

import { useEffect, useMemo, useState } from "react";
import Link from "next/link";

type GlobusProject = {
  id: string;
  code: string;
  name: string;
  description: string;
  kind: string;
  status: string;
  priority: number;
  tags: string[];
};

type Dot = {
  id: string;
  label: string;
  kind: "country" | "app";
  xPct: number; // 0..100 inside globe
  yPct: number; // 0..100 inside globe
  color: string;
  accent: string;
  href?: string;
  description?: string;
};

export default function HomePage() {
  const [projects, setProjects] = useState<GlobusProject[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const [qrightTotal, setQrightTotal] = useState<number>(0);
  const [qrightSignedTotal, setQrightSignedTotal] = useState<number>(0);
  const [qrightErr, setQrightErr] = useState<string | null>(null);

  const [selectedId, setSelectedId] = useState<string>("qright");

  useEffect(() => {
    const fetchProjects = async () => {
      try {
        const baseUrl =
          process.env.NEXT_PUBLIC_API_BASE_URL || "http://localhost:4001";

        const res = await fetch(`${baseUrl}/api/globus/projects`);
        if (!res.ok) throw new Error("Failed to load projects");

        const data = await res.json();
        setProjects(data.items || []);
      } catch (e) {
        setError((e as Error).message);
      } finally {
        setLoading(false);
      }
    };

    fetchProjects();
  }, []);

  useEffect(() => {
    const fetchQrightStats = async () => {
      try {
        const baseUrl =
          process.env.NEXT_PUBLIC_API_BASE_URL || "http://localhost:4001";

        const [allRes, signedRes] = await Promise.all([
          fetch(`${baseUrl}/api/qright/objects`),
          fetch(`${baseUrl}/api/qright/objects/signed`),
        ]);

        if (!allRes.ok) throw new Error("Не удалось загрузить QRight (все)");
        if (!signedRes.ok)
          throw new Error("Не удалось загрузить QRight (подписанные)");

        const allData = await allRes.json();
        const signedData = await signedRes.json();

        setQrightTotal(allData?.total ?? 0);
        setQrightSignedTotal(signedData?.total ?? 0);
      } catch (e) {
        setQrightErr((e as Error).message);
      }
    };

    fetchQrightStats();
  }, []);

  const countryDots: Dot[] = useMemo(
    () => [
      {
        id: "RU",
        label: "Россия",
        kind: "country",
        xPct: 46,
        yPct: 42,
        color: "#2e7d32",
        accent: "#2e7d32",
        description: "Регион участников и проектов AEVION.",
      },
      {
        id: "EU",
        label: "Европа",
        kind: "country",
        xPct: 39,
        yPct: 38,
        color: "#1565c0",
        accent: "#1565c0",
        description: "Европейские ветки и интеграции.",
      },
      {
        id: "US",
        label: "США",
        kind: "country",
        xPct: 30,
        yPct: 48,
        color: "#ef6c00",
        accent: "#ef6c00",
        description: "Западная зона экспериментов.",
      },
      {
        id: "ASIA",
        label: "Азия",
        kind: "country",
        xPct: 60,
        yPct: 50,
        color: "#00897b",
        accent: "#00897b",
        description: "Азиатские агентные сценарии и контент.",
      },
      {
        id: "AF",
        label: "Африка",
        kind: "country",
        xPct: 54,
        yPct: 62,
        color: "#5d4037",
        accent: "#5d4037",
        description: "Проекты сообщества.",
      },
    ],
    []
  );

  const appDots: Dot[] = useMemo(
    () => [
      {
        id: "qright",
        label: "QRight",
        kind: "app",
        xPct: 52,
        yPct: 36,
        color: "#2e7d32",
        accent: "#2e7d32",
        href: "/qright",
        description: "Электронная регистрация: реестр объектов и подпись.",
      },
      {
        id: "qsign",
        label: "QSign",
        kind: "app",
        xPct: 44,
        yPct: 56,
        color: "#1565c0",
        accent: "#1565c0",
        href: "/qsign",
        description: "Подпись и проверка целостности (HMAC).",
      },
      {
        id: "aevion-ip-bureau",
        label: "IP Bureau",
        kind: "app",
        xPct: 58,
        yPct: 44,
        color: "#6d4c41",
        accent: "#a1887f",
        href: "/aevion-ip-bureau",
        description: "Сертификаты на основе подписанного QRight.",
      },
      {
        id: "auth",
        label: "Auth",
        kind: "app",
        xPct: 40,
        yPct: 70,
        color: "#5c6bc0",
        accent: "#9fa8da",
        href: "/auth",
        description: "Регистрация и логин участников.",
      },
      {
        id: "qtrade",
        label: "QTrade",
        kind: "app",
        xPct: 72,
        yPct: 40,
        color: "#00897b",
        accent: "#4db6ac",
        href: "/qtrade",
        description: "Счета, пополнение и переводы (MVP).",
      },
      {
        id: "oscar-ai",
        label: "Oscar AI",
        kind: "app",
        xPct: 31,
        yPct: 58,
        color: "#6a1b9a",
        accent: "#6a1b9a",
        href: "/oscar-ai",
        description: "Кино-участия и защита авторства (MVP).",
      },
      {
        id: "grammy-ai",
        label: "Grammy AI",
        kind: "app",
        xPct: 67,
        yPct: 58,
        color: "#ef6c00",
        accent: "#ef6c00",
        href: "/grammy-ai",
        description: "Музыка-участия и защита авторства (MVP).",
      },
      {
        id: "cyberchess",
        label: "CyberChess",
        kind: "app",
        xPct: 56,
        yPct: 70,
        color: "#37474f",
        accent: "#90a4ae",
        href: "/cyberchess",
        description: "Шахматная платформа: игроки, партии, записи ходов.",
      },
    ],
    []
  );

  const selectedDot = useMemo(() => {
    const all = [...countryDots, ...appDots];
    return all.find((d) => d.id === selectedId) || null;
  }, [countryDots, appDots, selectedId]);

  const displayedApps = useMemo(() => {
    const baseApps = projects.map((p) => ({
      id: p.id,
      code: p.code,
      name: p.name,
      kind: p.kind,
      status: p.status,
      tags: p.tags,
    }));

    baseApps.push(
      {
        id: "oscar-ai",
        code: "OSCAR",
        name: "Oscar AI — Kino",
        kind: "app",
        status: "demo",
        tags: ["movie", "ai", "rights"],
      },
      {
        id: "grammy-ai",
        code: "GRAMMY",
        name: "Grammy AI — Music",
        kind: "app",
        status: "demo",
        tags: ["music", "ai", "rights"],
      }
    );

    return baseApps;
  }, [projects]);

  if (loading) return <div style={{ padding: 20 }}>Загрузка проектов…</div>;
  if (error) return <div style={{ padding: 20 }}>Ошибка: {error}</div>;

  return (
    <main style={{ padding: 20 }}>
      <h1 style={{ fontSize: 26, marginBottom: 16 }}>AEVION Globus v1</h1>

      <section
        style={{
          border: "1px solid #ddd",
          borderRadius: 14,
          padding: 14,
          marginBottom: 18,
          background: "#fff",
        }}
      >
        <div style={{ fontWeight: 800, fontSize: 18, marginBottom: 8 }}>
          Планета возможностей и электронного авторского права
        </div>

        {qrightErr && (
          <div style={{ color: "crimson", marginBottom: 10 }}>
            {qrightErr}
          </div>
        )}

        <div
          style={{
            display: "grid",
            gridTemplateColumns: "1.2fr 1fr",
            gap: 14,
            alignItems: "start",
          }}
        >
          <div
            style={{
              border: "1px solid #ddd",
              borderRadius: 14,
              padding: 12,
              background: "#fafafa",
            }}
          >
            <div style={{ fontWeight: 800, fontSize: 14, marginBottom: 8 }}>
              Псевдо-глобус (точки стран и приложений)
            </div>

            <div
              style={{
                width: "100%",
                maxWidth: 520,
                margin: "0 auto",
                aspectRatio: "1 / 1",
                borderRadius: "50%",
                position: "relative",
                overflow: "hidden",
                background:
                  "radial-gradient(circle at 35% 30%, #d9f1ff 0%, #72b9ee 18%, #1e6fbe 34%, #073e5d 62%, #041a33 100%)",
                boxShadow: "inset 0 0 0 2px rgba(255,255,255,0.18)",
              }}
            >
              <div
                style={{
                  position: "absolute",
                  inset: 0,
                  backgroundImage:
                    "linear-gradient(to right, rgba(255,255,255,0.12) 1px, transparent 1px), linear-gradient(to bottom, rgba(255,255,255,0.12) 1px, transparent 1px)",
                  backgroundSize: "28px 28px",
                  opacity: 0.35,
                  maskImage:
                    "radial-gradient(circle at center, rgba(0,0,0,1) 56%, rgba(0,0,0,0) 100%)",
                }}
              />
              {/* Условные континенты (псевдо-глобус): земные зелёно-коричневые оттенки */}
              <div
                style={{
                  position: "absolute",
                  inset: 0,
                  background:
                    "radial-gradient(circle at 26% 36%, rgba(46,125,50,0.55) 0%, rgba(46,125,50,0) 36%), radial-gradient(circle at 62% 42%, rgba(27,94,32,0.45) 0%, rgba(27,94,32,0) 38%), radial-gradient(circle at 54% 66%, rgba(93,64,55,0.40) 0%, rgba(93,64,55,0) 36%)",
                  mixBlendMode: "multiply",
                  opacity: 0.9,
                  pointerEvents: "none",
                }}
              />

              {[...countryDots, ...appDots].map((d) => {
                const active = d.id === selectedId;
                const size = active ? 14 : 9;
                const ring = active
                  ? "0 0 0 2px rgba(255,255,255,0.8), 0 0 18px rgba(255,255,255,0.35)"
                  : "none";
                return (
                  <button
                    key={d.id}
                    type="button"
                    onClick={() => setSelectedId(d.id)}
                    style={{
                      position: "absolute",
                      left: `${d.xPct}%`,
                      top: `${d.yPct}%`,
                      transform: "translate(-50%, -50%)",
                      width: size,
                      height: size,
                      borderRadius: 999,
                      border: "none",
                      background: d.accent,
                      cursor: "pointer",
                      boxShadow: ring,
                      outline: "none",
                      opacity: active ? 1 : 0.95,
                    }}
                    title={d.label}
                  />
                );
              })}
            </div>

            <div style={{ marginTop: 10, display: "flex", gap: 10, flexWrap: "wrap" }}>
              <button
                type="button"
                onClick={() => setSelectedId("qright")}
                style={{
                  padding: "8px 12px",
                  borderRadius: 8,
                  border: "1px solid #0a5",
                  background: selectedId === "qright" ? "#0a5" : "#fff",
                  color: selectedId === "qright" ? "#fff" : "#0a5",
                  cursor: "pointer",
                  fontSize: 13,
                }}
              >
                QRight
              </button>
              <button
                type="button"
                onClick={() => setSelectedId("qsign")}
                style={{
                  padding: "8px 12px",
                  borderRadius: 8,
                  border: "1px solid #0a5",
                  background: selectedId === "qsign" ? "#0a5" : "#fff",
                  color: selectedId === "qsign" ? "#fff" : "#0a5",
                  cursor: "pointer",
                  fontSize: 13,
                }}
              >
                QSign
              </button>
              <Link
                href="/auth"
                style={{
                  color: "#0a5",
                  textDecoration: "none",
                  border: "1px solid #0a5",
                  borderRadius: 8,
                  padding: "8px 12px",
                  display: "inline-block",
                  fontSize: 13,
                }}
              >
                Вход участников
              </Link>
            </div>
          </div>

          <div
            style={{
              border: "1px solid #ddd",
              borderRadius: 14,
              padding: 12,
              background: "#fff",
            }}
          >
            <div style={{ fontWeight: 800, fontSize: 14, marginBottom: 8 }}>
              Приложения и авторское право
            </div>

            {selectedDot ? (
              <div style={{ marginBottom: 12 }}>
                <div style={{ display: "flex", justifyContent: "space-between", gap: 10 }}>
                  <div style={{ fontWeight: 800, fontSize: 16 }}>{selectedDot.label}</div>
                  <div style={{ fontSize: 12, color: "#666" }}>
                    {selectedDot.kind === "country" ? "страна" : "приложение"}
                  </div>
                </div>
                <div style={{ color: "#666", fontSize: 13, marginTop: 6 }}>
                  {selectedDot.description || "—"}
                </div>
                {selectedDot.kind === "app" && selectedDot.href ? (
                  <div style={{ marginTop: 10 }}>
                    <Link
                      href={selectedDot.href}
                      style={{
                        color: selectedDot.color,
                        textDecoration: "none",
                        border: `1px solid ${selectedDot.color}`,
                        borderRadius: 8,
                        padding: "8px 12px",
                        display: "inline-block",
                        fontSize: 13,
                      }}
                    >
                      Открыть
                    </Link>
                  </div>
                ) : null}
              </div>
            ) : (
              <div style={{ color: "#666", fontSize: 13, marginBottom: 12 }}>
                Выберите точку на глобусе.
              </div>
            )}

            <div style={{ marginBottom: 10, color: "#666", fontSize: 13 }}>
              QRight всего: <b>{qrightTotal}</b>, подписанные: <b>{qrightSignedTotal}</b>
            </div>

            <div style={{ overflowX: "auto" }}>
              <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 13 }}>
                <thead>
                  <tr>
                    <th style={{ textAlign: "left", padding: "8px 6px", borderBottom: "1px solid #eee" }}>
                      Приложение
                    </th>
                    <th style={{ textAlign: "left", padding: "8px 6px", borderBottom: "1px solid #eee" }}>
                      Направление
                    </th>
                    <th style={{ textAlign: "left", padding: "8px 6px", borderBottom: "1px solid #eee" }}>
                      Агенты
                    </th>
                    <th style={{ textAlign: "left", padding: "8px 6px", borderBottom: "1px solid #eee" }}>
                      Авторское право
                    </th>
                  </tr>
                </thead>
                <tbody>
                  {displayedApps.map((app) => (
                    <tr key={app.id}>
                      <td style={{ padding: "8px 6px", borderBottom: "1px solid #f3f3f3" }}>
                        <b>{app.code}</b>
                        <div style={{ color: "#666", fontSize: 12, marginTop: 2 }}>
                          {app.status}
                        </div>
                      </td>
                      <td style={{ padding: "8px 6px", borderBottom: "1px solid #f3f3f3" }}>
                        {app.kind}
                      </td>
                      <td style={{ padding: "8px 6px", borderBottom: "1px solid #f3f3f3" }}>
                        {app.id === "qright"
                          ? "реестр"
                          : app.id === "qsign"
                            ? "верификация"
                            : app.id === "aevion-ip-bureau"
                              ? "сертификаты"
                              : app.id === "auth"
                                ? "участники"
                                : app.id === "qtrade"
                                  ? "счета"
                                  : app.id === "cyberchess"
                                    ? "партии"
                                    : app.id === "oscar-ai" || app.id === "grammy-ai"
                                      ? "витрина участия"
                                      : "слоты"}
                      </td>
                      <td style={{ padding: "8px 6px", borderBottom: "1px solid #f3f3f3" }}>
                        QRight реестр
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>

            <div style={{ marginTop: 12, display: "flex", gap: 10, flexWrap: "wrap" }}>
              <Link
                href="/qright"
                style={{
                  color: "#0a5",
                  textDecoration: "none",
                  border: "1px solid #0a5",
                  borderRadius: 8,
                  padding: "8px 12px",
                  display: "inline-block",
                  fontSize: 13,
                }}
              >
                QRight
              </Link>
              <Link
                href="/qsign"
                style={{
                  color: "#0a5",
                  textDecoration: "none",
                  border: "1px solid #0a5",
                  borderRadius: 8,
                  padding: "8px 12px",
                  display: "inline-block",
                  fontSize: 13,
                }}
              >
                QSign
              </Link>
              <Link
                href="/oscar-ai"
                style={{
                  color: "#66f",
                  textDecoration: "none",
                  border: "1px solid #66f",
                  borderRadius: 8,
                  padding: "8px 12px",
                  display: "inline-block",
                  fontSize: 13,
                }}
              >
                Oscar AI
              </Link>
              <Link
                href="/grammy-ai"
                style={{
                  color: "#f90",
                  textDecoration: "none",
                  border: "1px solid #f90",
                  borderRadius: 8,
                  padding: "8px 12px",
                  display: "inline-block",
                  fontSize: 13,
                }}
              >
                Grammy AI
              </Link>
            </div>
          </div>
        </div>
      </section>

      <div style={{ marginBottom: 15 }}>
        Всего проектов: <b>{projects.length}</b>
        <span style={{ color: "#666", marginLeft: 10, fontSize: 13 }}>
          (кликай по точкам на глобусе)
        </span>
      </div>
    </main>
  );
}
